using Microsoft.UI.Xaml.Controls;\nusing PartTracker.Services;\nusing Serilog;\n\nnamespace PartTracker.Views\n{\n    public sealed partial class CreateUserDialog : ContentDialog\n    {\n        private readonly DatabaseService _db;\n        private readonly AuthService _auth;\n        private readonly ILogger _logger;\n\n        public CreateUserDialog()\n        {\n            InitializeComponent();\n            _db = new DatabaseService();\n            _auth = new AuthService(_db);\n            _logger = new LoggerConfiguration()\n                .WriteTo.File(\"logs/ui.log\", rollingInterval: RollingInterval.Day)\n                .CreateLogger();\n\n            this.PrimaryButtonClick += OnCreateClick;\n        }\n\n        private async void OnCreateClick(ContentDialog sender, ContentDialogButtonClickEventArgs args)\n        {\n            try\n            {\n                string username = UsernameInput.Text?.Trim() ?? \"\";\n                string password = PasswordInput.Password ?? \"\";\n                string role = (RoleCombo.SelectedItem as ComboBoxItem)?.Content.ToString() ?? \"Mechanic\";\n\n                if (string.IsNullOrEmpty(username) || string.IsNullOrEmpty(password))\n                {\n                    ErrorMessage.Text = \"Vyplňte prosím ID a heslo\";\n                    args.Cancel = true;\n                    return;\n                }\n\n                bool success = await _auth.CreateUserAsync(username, password, role);\n\n                if (success)\n                {\n                    _logger.Information($\"Admin created new user: {username} ({role})\");\n                }\n                else\n                {\n                    ErrorMessage.Text = \"Chyba: Uživatel s tímto ID již existuje\";\n                    args.Cancel = true;\n                }\n            }\n            catch (Exception ex)\n            {\n                ErrorMessage.Text = $\"Chyba: {ex.Message}\";\n                _logger.Error($\"Error creating user: {ex.Message}\");\n                args.Cancel = true;\n            }\n        }\n    }\n}